INSERT INTO grammar_topics (slug, title, cefr_level, explanation, tags, sort_order)
VALUES
  ('present-perfect', '현재완료', 'A2', '과거에 시작해 지금까지 이어지거나 영향을 주는 일은 현재완료(have/has + p.p.)로 나타낸다. 기간은 for, 시점은 since와 함께 쓰고, 구체적 과거 시점(yesterday 등)과는 함께 쓰지 않는다.', ARRAY['tense']::TEXT[], 1),
  ('past-simple', '과거시제', 'A2', '이미 끝난 과거의 동작이나 상태는 과거시제로 나타낸다. 규칙 동사는 -ed를 붙이고, 의문문과 부정문에서는 did를 쓰며 본동사는 원형으로 돌아간다.', ARRAY['tense']::TEXT[], 2),
  ('articles', '관사 a/an/the', 'A2', '처음 언급하는 셀 수 있는 단수 명사 앞에는 부정관사 a/an을, 특정한 것을 가리킬 때는 정관사 the를 쓴다. 모음 소리로 시작하는 단어 앞에는 an을 쓴다.', ARRAY['grammar-articles']::TEXT[], 3),
  ('countable-uncountable', '셀 수 있는 명사와 없는 명사', 'A2', '셀 수 있는 명사는 복수형이 가능하고 many와 함께 쓰며, 셀 수 없는 명사는 단수 취급하고 much와 함께 쓴다. 양을 말할 때는 some, a lot of 등을 활용한다.', ARRAY['grammar-articles']::TEXT[], 4),
  ('comparatives', '비교급과 최상급', 'A2', '두 대상을 비교할 때는 비교급(-er 또는 more)에 than을 쓰고, 셋 이상에서 가장 ~한 것은 최상급(-est 또는 most)에 the를 붙인다. 음절이 긴 형용사는 more/most를 쓴다.', ARRAY['comparison']::TEXT[], 5),
  ('prepositions-time', '시간 전치사', 'A2', '시각·구체적 시점에는 at, 요일·날짜에는 on, 월·연도·계절처럼 긴 기간에는 in을 쓴다. 마감이나 기한을 말할 때는 by와 until을 구별해 쓴다.', ARRAY['prepositions']::TEXT[], 6),
  ('prepositions-place', '장소 전치사', 'A2', '넓은 공간이나 도시·나라 안에는 in, 표면 위나 거리·층에는 on, 특정 지점에는 at을 쓴다. 위치 관계를 정확히 나타내려면 전치사 선택이 중요하다.', ARRAY['prepositions']::TEXT[], 7),
  ('future-will-going-to', '미래 will과 be going to', 'A2', '말하는 순간 결정한 일이나 단순 예측에는 will을, 이미 정해진 계획이나 근거 있는 예측에는 be going to를 쓴다. 두 표현 모두 미래를 나타내지만 뉘앙스가 다르다.', ARRAY['tense']::TEXT[], 8),
  ('modal-can-could', '조동사 can과 could', 'A2', 'can은 현재의 능력·허락·가능성을, could는 과거의 능력이나 더 공손한 요청·가능성을 나타낸다. 조동사 뒤에는 항상 동사원형을 쓴다.', ARRAY['modals']::TEXT[], 9),
  ('present-continuous', '현재진행형', 'A2', '지금 진행 중인 동작이나 일시적인 상황은 현재진행형(be동사 + 동사ing)으로 나타낸다. like, know처럼 상태를 나타내는 동사는 보통 진행형으로 쓰지 않는다.', ARRAY['tense']::TEXT[], 10),
  ('modal-should-must', '조동사 should/must', 'A2', 'should는 충고나 권유를, must는 강한 의무나 확신을 나타냅니다. 뒤에는 항상 동사원형이 옵니다.', ARRAY['modals']::TEXT[], 11),
  ('conditionals-first', '가정법 1형식 (if + 현재)', 'B1', '실현 가능한 미래의 일을 말할 때 if절에는 현재시제, 주절에는 will을 씁니다. 일어날 법한 조건과 결과를 나타냅니다.', ARRAY['conditionals']::TEXT[], 12),
  ('conditionals-second', '가정법 2형식 (if + 과거)', 'B1', '현재 사실과 반대되거나 일어날 가능성이 낮은 일을 가정할 때 if절에는 과거시제, 주절에는 would를 씁니다. be동사는 was 대신 were를 자주 씁니다.', ARRAY['conditionals']::TEXT[], 13),
  ('passive-voice', '수동태', 'B1', '동작의 대상이 주어가 될 때 수동태를 쓰며 ''be동사 + 과거분사'' 형태입니다. 행위자는 by로 나타냅니다.', ARRAY['passive']::TEXT[], 14),
  ('relative-clauses', '관계대명사', 'B1', '관계대명사는 두 문장을 연결하며 사람에는 who, 사물에는 which, 둘 다에는 that을 씁니다. 선행사를 꾸며주는 절을 이끕니다.', ARRAY['clauses']::TEXT[], 15),
  ('gerund-infinitive', '동명사 vs to부정사', 'B1', '동사에 따라 뒤에 동명사(-ing)나 to부정사가 옵니다. enjoy, finish는 동명사를, want, decide는 to부정사를 취합니다.', ARRAY['verb-patterns']::TEXT[], 16),
  ('question-tags', '부가의문문', 'A2', '부가의문문은 문장 끝에 짧게 덧붙이는 의문문입니다. 앞이 긍정이면 부정, 부정이면 긍정으로 만들고 같은 시제의 조동사를 씁니다.', ARRAY['questions']::TEXT[], 17),
  ('adverbs-frequency', '빈도 부사', 'A2', 'always, usually, often, sometimes, never 같은 빈도 부사는 일반동사 앞, be동사 뒤에 위치합니다. 얼마나 자주 하는지를 나타냅니다.', ARRAY['adverbs']::TEXT[], 18),
  ('too-enough', 'too / enough', 'A2', 'too는 형용사 앞에서 ''너무 ~한''을, enough는 형용사 뒤에서 ''충분히 ~한''을 나타냅니다. too는 부정적 의미, enough는 충분함을 표현합니다.', ARRAY['comparison']::TEXT[], 19),
  ('used-to', 'used to', 'A2', 'used to는 과거에 습관적으로 했지만 지금은 하지 않는 일을 나타냅니다. 뒤에는 항상 동사원형이 오며 부정은 didn''t use to입니다.', ARRAY['tense']::TEXT[], 20)
INSERT INTO grammar_questions (topic_id, question_type, prompt, options, correct_answer, explanation, sort_order)
VALUES
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'word_order', '그는 여기서 5년째 일해 왔다.', '{"chips": ["He", "has", "worked", "here", "for", "five", "years"]}'::JSONB, 'He has worked here for five years.', 'has worked — 현재완료 + for + 기간으로 지속을 나타낸다.', 1),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'word_order', '나는 그 영화를 이미 봤다.', '{"chips": ["I", "have", "already", "seen", "that", "movie"]}'::JSONB, 'I have already seen that movie.', 'already는 have와 과거분사 사이에 놓는다.', 2),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'word_order', '우리는 2020년부터 서울에 살았다.', '{"chips": ["We", "have", "lived", "in", "Seoul", "since", "2020"]}'::JSONB, 'We have lived in Seoul since 2020.', 'since + 시작 시점은 현재완료와 함께 쓴다.', 3),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'blank_choice', 'She ___ finished the report.', '{"choices": ["has", "have", "had"]}'::JSONB, 'has', '3인칭 단수 주어 She에는 has를 쓴다.', 4),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'blank_choice', 'I have lived here ___ ten years.', '{"choices": ["since", "for", "from"]}'::JSONB, 'for', '기간(ten years) 앞에는 for를 쓴다.', 5),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'blank_choice', 'They have ___ arrived at the airport.', '{"choices": ["yet", "just", "ago"]}'::JSONB, 'just', 'just는 ''방금''의 의미로 현재완료와 자연스럽다. ago는 과거시제와만 쓴다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'blank_choice', 'Have you ___ been to Japan?', '{"choices": ["ever", "already", "since"]}'::JSONB, 'ever', '의문문에서 ''~한 적 있니''는 ever를 쓴다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'error_find', '틀린 부분을 고르세요: She have finished the work.', '{"segments": ["She", "have", "finished", "the work"]}'::JSONB, 'have', '주어가 3인칭 단수이므로 have가 아니라 has를 써야 한다.', 8),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'error_find', '틀린 부분을 고르세요: I have seen him yesterday.', '{"segments": ["I", "have seen", "him", "yesterday"]}'::JSONB, 'yesterday', '구체적 과거 시점 yesterday는 현재완료와 함께 쓸 수 없다.', 9),
  ((SELECT id FROM grammar_topics WHERE slug = 'present-perfect'), 'error_find', '틀린 부분을 고르세요: We have lived here since five years.', '{"segments": ["We", "have lived", "here", "since five years"]}'::JSONB, 'since five years', '기간 five years 앞에는 since가 아니라 for를 써야 한다.', 10),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'word_order', '나는 어제 새 노트북을 샀다.', '{"chips": ["I", "bought", "a", "new", "laptop", "yesterday"]}'::JSONB, 'I bought a new laptop yesterday.', 'buy의 과거형은 bought이고, yesterday로 과거 시점을 명시한다.', 1),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'word_order', '그들은 지난주에 회의에 참석했다.', '{"chips": ["They", "attended", "the", "meeting", "last", "week"]}'::JSONB, 'They attended the meeting last week.', '규칙동사 attend의 과거형 attended를 쓴다.', 2),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'word_order', '그녀는 2시간 전에 떠났다.', '{"chips": ["She", "left", "two", "hours", "ago"]}'::JSONB, 'She left two hours ago.', 'leave의 과거형 left와 ago는 과거시제와 함께 쓴다.', 3),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'word_order', '우리는 그 식당에서 점심을 먹지 않았다.', '{"chips": ["We", "did", "not", "have", "lunch", "there"]}'::JSONB, 'We did not have lunch there.', '부정문은 did not + 동사원형(have)으로 만든다.', 4),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'blank_choice', 'He ___ to the office early yesterday.', '{"choices": ["went", "goes", "has gone"]}'::JSONB, 'went', 'yesterday가 있으므로 과거시제 went를 쓴다.', 5),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'blank_choice', 'They ___ not finish the project on time.', '{"choices": ["did", "do", "were"]}'::JSONB, 'did', '일반동사 부정의 과거형은 did not이다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'blank_choice', 'Did you ___ the email this morning?', '{"choices": ["send", "sent", "sending"]}'::JSONB, 'send', 'did 다음에는 동사원형 send를 쓴다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'blank_choice', 'The store ___ at nine last night.', '{"choices": ["closed", "closes", "close"]}'::JSONB, 'closed', '과거 시점(last night)이므로 과거형 closed를 쓴다.', 8),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'error_find', '틀린 부분을 고르세요: She buyed a ticket last Friday.', '{"segments": ["She", "buyed", "a ticket", "last Friday"]}'::JSONB, 'buyed', 'buy는 불규칙동사로 과거형이 bought이다.', 9),
  ((SELECT id FROM grammar_topics WHERE slug = 'past-simple'), 'error_find', '틀린 부분을 고르세요: We did went home after work.', '{"segments": ["We", "did", "went", "home"]}'::JSONB, 'went', 'did가 있으면 본동사는 원형 go를 써야 한다.', 10),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'word_order', '그녀는 한 시간 안에 보고서를 끝냈다.', '{"chips": ["She", "finished", "the", "report", "in", "an", "hour"]}'::JSONB, 'She finished the report in an hour.', 'an hour는 h가 묵음이라 모음 소리로 시작해 an을 쓴다.', 1),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'word_order', '그는 정직한 직원을 찾고 있다.', '{"chips": ["He", "is", "looking", "for", "an", "honest", "employee"]}'::JSONB, 'He is looking for an honest employee.', 'honest는 h가 묵음이므로 an을 쓴다.', 2),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'word_order', '그 책은 탁자 위에 있다.', '{"chips": ["The", "book", "is", "on", "that", "table"]}'::JSONB, 'The book is on that table.', '특정한 책을 가리키므로 the를 쓴다.', 3),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'blank_choice', 'I bought ___ umbrella this morning.', '{"choices": ["an", "a", "the"]}'::JSONB, 'an', 'umbrella는 모음 소리로 시작하므로 an을 쓴다.', 4),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'blank_choice', 'She is ___ university student in London.', '{"choices": ["a", "an", "the"]}'::JSONB, 'a', 'university는 발음이 ''유''로 자음 소리라서 a를 쓴다.', 5),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'blank_choice', 'Can you pass me ___ salt, please?', '{"choices": ["the", "a", "an"]}'::JSONB, 'the', '식탁 위의 특정 소금을 가리키므로 the를 쓴다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'blank_choice', 'He works as ___ engineer at a startup.', '{"choices": ["an", "a", "the"]}'::JSONB, 'an', 'engineer는 모음 소리로 시작하므로 an을 쓴다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'error_find', '틀린 부분을 고르세요: She is a honest manager.', '{"segments": ["She is", "a", "honest", "manager"]}'::JSONB, 'a', 'honest는 모음 소리로 시작하므로 an을 써야 한다.', 8),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'error_find', '틀린 부분을 고르세요: He gave me an useful tip.', '{"segments": ["He gave me", "an", "useful", "tip"]}'::JSONB, 'an', 'useful은 ''유''로 자음 소리라서 a를 써야 한다.', 9),
  ((SELECT id FROM grammar_topics WHERE slug = 'articles'), 'error_find', '틀린 부분을 고르세요: Please open a window near you.', '{"segments": ["Please open", "a", "window", "near you"]}'::JSONB, 'a', '특정한 창문을 가리키므로 the가 더 자연스럽다.', 10),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'word_order', '책상 위에 많은 정보가 있다.', '{"chips": ["There", "is", "much", "information", "on", "the", "desk"]}'::JSONB, 'There is much information on the desk.', 'information은 불가산명사라 much와 함께 쓴다.', 1),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'word_order', '우리는 약간의 조언이 필요하다.', '{"chips": ["We", "need", "a", "little", "advice"]}'::JSONB, 'We need a little advice.', 'advice는 불가산명사라 a little과 함께 쓴다.', 2),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'word_order', '회의에 많은 사람들이 왔다.', '{"chips": ["Many", "people", "came", "to", "the", "meeting"]}'::JSONB, 'Many people came to the meeting.', 'people은 가산명사라 many와 함께 쓴다.', 3),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'blank_choice', 'How ___ money do you have?', '{"choices": ["much", "many", "few"]}'::JSONB, 'much', 'money는 불가산명사라 much를 쓴다.', 4),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'blank_choice', 'There aren''t ___ chairs in the room.', '{"choices": ["many", "much", "little"]}'::JSONB, 'many', 'chairs는 가산명사라 many를 쓴다.', 5),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'blank_choice', 'I''d like some ___ , please.', '{"choices": ["water", "waters", "a water"]}'::JSONB, 'water', 'water는 불가산명사라 복수형을 쓰지 않는다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'blank_choice', 'She gave me a useful ___ .', '{"choices": ["piece of advice", "advices", "advice piece"]}'::JSONB, 'piece of advice', 'advice는 불가산이라 a piece of advice로 센다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'error_find', '틀린 부분을 고르세요: I have many homeworks tonight.', '{"segments": ["I have", "many", "homeworks", "tonight"]}'::JSONB, 'homeworks', 'homework는 불가산명사라 복수형 homeworks가 없다.', 8),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'error_find', '틀린 부분을 고르세요: How much books did you buy?', '{"segments": ["How", "much", "books", "did you buy"]}'::JSONB, 'much', 'books는 가산명사라 much가 아니라 many를 써야 한다.', 9),
  ((SELECT id FROM grammar_topics WHERE slug = 'countable-uncountable'), 'error_find', '틀린 부분을 고르세요: We made a good progress today.', '{"segments": ["We made", "a", "good progress", "today"]}'::JSONB, 'a', 'progress는 불가산명사라 부정관사 a를 붙일 수 없다.', 10),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'word_order', '이 가방이 저것보다 더 비싸다.', '{"chips": ["This", "bag", "is", "more", "expensive", "than", "that"]}'::JSONB, 'This bag is more expensive than that.', 'expensive는 긴 형용사라 more를 쓰고 than으로 비교한다.', 1),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'word_order', '그녀는 반에서 가장 키가 크다.', '{"chips": ["She", "is", "the", "tallest", "in", "her", "class"]}'::JSONB, 'She is the tallest in her class.', '최상급 tallest 앞에는 the를 붙인다.', 2),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'word_order', '오늘이 어제보다 더 춥다.', '{"chips": ["Today", "is", "colder", "than", "yesterday"]}'::JSONB, 'Today is colder than yesterday.', 'cold의 비교급은 colder이고 than과 함께 쓴다.', 3),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'blank_choice', 'This phone is ___ than mine.', '{"choices": ["cheaper", "cheapest", "more cheap"]}'::JSONB, 'cheaper', '둘을 비교하므로 비교급 cheaper를 쓴다.', 4),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'blank_choice', 'It was the ___ day of the year.', '{"choices": ["hottest", "hotter", "most hot"]}'::JSONB, 'hottest', 'hot의 최상급은 자음을 겹쳐 hottest이다.', 5),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'blank_choice', 'Her idea is ___ interesting than his.', '{"choices": ["more", "most", "much"]}'::JSONB, 'more', 'interesting은 긴 형용사라 비교급에 more를 쓴다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'blank_choice', 'He runs ___ than his brother.', '{"choices": ["faster", "fastest", "more fast"]}'::JSONB, 'faster', 'fast의 비교급은 faster이다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'comparatives'), 'error_find', '틀린 부분을 고르세요: This box is more heavier than that one.', '{"segments": ["This box is", "more", "heavier", "than that one"]}'::JSONB, 'more', 'heavier가 이미 비교급이므로 more를 함께 쓰면 안 된다.', 8),
