  ((SELECT id FROM grammar_topics WHERE slug = 'used-to'), 'word_order', '나는 매일 우유를 마시곤 했다.', '{"chips": ["I", "used", "to", "drink", "milk", "every", "day"]}'::JSONB, 'I used to drink milk every day.', 'used to + 동사원형 drink로 과거 습관을 나타냅니다.', 6),
  ((SELECT id FROM grammar_topics WHERE slug = 'used-to'), 'word_order', '그녀는 발레를 배우곤 했다.', '{"chips": ["She", "used", "to", "learn", "ballet"]}'::JSONB, 'She used to learn ballet.', '과거의 습관을 used to learn으로 표현합니다.', 7),
  ((SELECT id FROM grammar_topics WHERE slug = 'used-to'), 'word_order', '우리는 그곳에 자주 가곤 했다.', '{"chips": ["We", "used", "to", "go", "there", "often"]}'::JSONB, 'We used to go there often.', 'used to 뒤에 동사원형 go가 와서 과거 습관을 나타냅니다.', 8),
